ALTER TABLE public.auftrag_zahlungsereignisse DROP CONSTRAINT IF EXISTS auftrag_zahlungsereignisse_payment_type_chk; ALTER TABLE public.auftrag_zahlungsereignisse ADD CONSTRAINT auftrag_zahlungsereignisse_payment_type_chk CHECK (payment_type IN ('abbruch_bezahlt','teilweise_bezahlt','erledigt_bezahlt','sonstige_zahlung')); UPDATE public.auftrag_zahlungsereignisse SET payment_type = CASE WHEN lower(coalesce(status_label,'') || ' ' || coalesce(status_key,'')) LIKE '%abbruch%' THEN 'abbruch_bezahlt' WHEN lower(coalesce(status_label,'') || ' ' || coalesce(status_key,'')) LIKE '%teil%' THEN 'teilweise_bezahlt' ELSE 'erledigt_bezahlt' END; INSERT INTO public.auftrag_zahlungsereignis_umsatz (ereignis_id, umsatz, positionen) SELECT e.id, 0, '[]'::jsonb FROM public.auftrag_zahlungsereignisse e LEFT JOIN public.auftrag_zahlungsereignis_umsatz u ON u.ereignis_id = e.id WHERE u.ereignis_id IS NULL; DROP TRIGGER IF EXISTS trg_create_zahlungsereignis ON public.auftrag_status_zuweisungen; DROP TRIGGER IF EXISTS trg_void_zahlungsereignis ON public.auftrag_status_zuweisungen;